using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Secção "Emblemas" (Tarefa #35 — Restructurar menus) — tela separada
/// dedicada exclusivamente aos emblemas de Gaia, Apolo, Zeus e dos mundos.
///
/// Anteriormente, os emblemas faziam parte da secção Progresso
/// (<see cref="ProgressSectionUI"/>). Esta secção separada permite:
/// - Mais espaço de ecrã para cada nó de emblema.
/// - Colocação num menu secundário (<see cref="SecondaryMenuController"/>,
///   acessível via "-") sem ocupar espaço no menu de pausa principal ("+").
///
/// Usa o mesmo prefab <see cref="EmblemNodeUI"/> e lógica de
/// <c>ProgressSectionUI.RefreshEmblems()</c>, mas sem os cartões de mundo.
///
/// Montagem no Editor:
/// - "root": GameObject do painel desta secção.
/// - "emblemsContainer"/"emblemNodePrefab": grelha de nós de emblema.
/// - "allEmblems": todos os EmblemData (Gaia, Apolo, Zeus + um por mundo).
/// - "allAreas/allForms/allMissions": usados para calcular <see cref="totalPercentText"/>.
/// - "firstSelectable": primeiro controlo a seleccionar ao abrir esta secção.
/// </summary>
/// <summary>
/// Implementa <see cref="ISecondaryMenuTab"/> para poder ser colocada no
/// <see cref="SecondaryMenuController"/> (menu "-"). Também implementa
/// <see cref="IPauseMenuSection"/> para compatibilidade com o menu de pausa
/// principal ("+"), caso o designer prefira colocá-la aí.
/// </summary>
public class EmblemsSectionUI : MonoBehaviour, ISecondaryMenuTab, IPauseMenuSection
{
    [Header("Framework")]
    [SerializeField] private GameObject root;

    [Tooltip("Primeiro controlo a seleccionar ao abrir esta secção.")]
    [SerializeField] private Selectable firstSelectable;

    [Header("Dados")]
    [Tooltip("Todos os EmblemData do jogo (Gaia, Apolo, Zeus, um por mundo). Mesma lista de ProgressSectionUI.allEmblems.")]
    [SerializeField] private List<EmblemData> allEmblems = new List<EmblemData>();

    [Tooltip("Necessário para calcular a % total — mesmo conjunto de ProgressSectionUI.")]
    [SerializeField] private List<AreaData> allAreas = new List<AreaData>();
    [SerializeField] private List<AnimalFormData> allForms = new List<AnimalFormData>();
    [SerializeField] private List<MissionData> allMissions = new List<MissionData>();

    [Header("Nós de Emblema")]
    [SerializeField] private Transform emblemsContainer;
    [SerializeField] private EmblemNodeUI emblemNodePrefab;

    [Header("Percentagem Total")]
    [SerializeField] private TMP_Text totalPercentText;
    [Tooltip("Formato da % total — {0} = percentagem (0-101). Ex: \"Conclusão total: {0}%\".")]
    [SerializeField] private string totalPercentFormat = "{0}%";

    // ISecondaryMenuTab
    public string TabName => "EMBLEMAS";

    // IPauseMenuSection
    public string SectionName => "EMBLEMAS";

    public GameObject Root => root != null ? root : gameObject;

    private readonly List<GameObject> spawnedEmblems = new List<GameObject>();

    // ---------------- ISecondaryMenuTab / IPauseMenuSection ----------------

    public void Refresh()
    {
        ClearSpawned();
        RefreshEmblems();
        RefreshTotalPercent();

        SelectFirst();
    }

    public void OnHide()
    {
        // Nada a limpar (emblemas são recriados em cada Refresh).
    }

    // ---------------- Emblemas ----------------

    private void RefreshEmblems()
    {
        if (emblemNodePrefab == null || emblemsContainer == null) return;

        var vars = GameVariables.Instance;

        foreach (var emblem in allEmblems)
        {
            if (emblem == null) continue;

            bool obtained = vars != null && !string.IsNullOrEmpty(emblem.obtainedVariable) && vars.GetBool(emblem.obtainedVariable);
            bool heardAbout = vars != null && !string.IsNullOrEmpty(emblem.heardAboutVariable) && vars.GetBool(emblem.heardAboutVariable);

            var node = Instantiate(emblemNodePrefab, emblemsContainer);
            node.gameObject.SetActive(true);
            node.Setup(emblem, obtained, heardAbout);
            spawnedEmblems.Add(node.gameObject);
        }
    }

    // ---------------- Percentagem Total ----------------

    private void RefreshTotalPercent()
    {
        if (totalPercentText == null) return;

        var progress = PlayerProgress.Instance;
        int percent = progress != null ? progress.GetTotalCompletionPercent(allAreas, allForms, allMissions, allEmblems) : 0;
        totalPercentText.text = string.Format(totalPercentFormat, percent);
    }

    // ---------------- Utilitários ----------------

    private void ClearSpawned()
    {
        foreach (var go in spawnedEmblems)
            if (go != null) Destroy(go);
        spawnedEmblems.Clear();
    }

    private void SelectFirst()
    {
        if (EventSystem.current != null && firstSelectable != null)
            EventSystem.current.SetSelectedGameObject(firstSelectable.gameObject);
    }
}
